    // Local Variables
    char name[50];

    // Input Statement
    printf("Enter your name: ");
    scanf("%s", name);

    // Function Call
    greetUser(name);

    return 0;
}

// User-defined Function
void greetUser(char name[]) {
    printf("Hello, %s! Welcome to C Programming.\n", name);
}

// PROCEDURAL PROGRAMMING APPROACH
// Problem: Calculate area and perimeter of a rectangle

// Declare global variables (if needed)
DECLARE length, width, area, perimeter

// Main Procedure
PROCEDURE main()
    // Get input from user
    OUTPUT "Enter length: "
    INPUT length
    OUTPUT "Enter width: "
    INPUT width

    // Call procedures to calculate
    area = calculateArea(length, width)
    perimeter = calculatePerimeter(length, width)

    // Display results
    OUTPUT "Area: ", area
    OUTPUT "Perimeter: ", perimeter
END PROCEDURE

// Function to calculate area
FUNCTION calculateArea(l, w)
    RETURN l * w
END FUNCTION

// Function to calculate perimeter
FUNCTION calculatePerimeter(l, w)
    RETURN 2 * (l + w)
END FUNCTION

// Call main to start program
CALL main()

// Class demonstrating Encapsulation
public class BankAccount {
    // Private data members - hidden from outside
    private String accountNumber;
    private String accountHolderName;
    private double balance;

    // Constructor
    public BankAccount(String accNo, String name, double initialBalance) {
        this.accountNumber = accNo;
        this.accountHolderName = name;
        this.balance = initialBalance;
    }

    // Public getter methods - controlled access
    public String getAccountNumber() {
        return accountNumber;
    }

    public String getAccountHolderName() {
        return accountHolderName;
    }

    public double getBalance() {
        return balance;
    }

    // Public setter method with validation - controlled modification
    public void deposit(double amount) {
        if (amount > 0) {
            balance += amount;
            System.out.println("Deposited: " + amount);
        } else {
            System.out.println("Invalid deposit amount");
        }
    }

    public void withdraw(double amount) {
        if (amount > 0 && amount <= balance) {
            balance -= amount;
            System.out.println("Withdrawn: " + amount);
        } else {
            System.out.println("Insufficient balance or invalid amount");
        }
    }
}

// Main class to test encapsulation
public class Main {
    public static void main(String[] args) {
        BankAccount account = new BankAccount("ACC123", "John Doe", 1000);

        // Cannot access balance directly - it is private
        // account.balance = 1000000; // This would cause an error

        // Must use public methods to interact with data
        account.deposit(500);
        account.withdraw(200);
        System.out.println("Current Balance: " + account.getBalance());
    }
}
